SELECT p.* FROM sys_product p WHERE p.deleted = 0 AND p.status IN ('在售', '可用', '上架') AND NOT EXISTS ( SELECT 1 FROM trade_order o WHERE o.product_id = p.id AND o.deleted = 0 AND o.status IN ('待付款', '待发货', '待收货') )
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))
AND p.type = 'service' AND p.category_id = #{category}
AND p.`condition` = #{condition}
AND p.price >= #{minPrice}
AND p.price <= #{maxPrice}
ORDER BY
p.price ASC p.price DESC p.favorite_count DESC, p.view_count DESC p.create_time DESC p.create_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM sys_product p WHERE p.deleted = 0
AND p.status IN ('在售', '可用', '上架')
AND NOT EXISTS (
    SELECT 1 FROM trade_order o
    WHERE o.product_id = p.id AND o.deleted = 0
    AND o.status IN ('待付款', '待发货', '待收货')
)

    AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))



        AND p.type = 'service'
        AND p.category_id = #{category}



    AND p.`condition` = #{condition}


    AND p.price >= #{minPrice}


    AND p.price <= #{maxPrice}

SELECT p.* FROM sys_product p WHERE p.deleted = 0 AND p.status IN ('可用', '上架', '在售') AND (p.type = 'service' OR p.type IS NULL OR p.type = '') AND NOT EXISTS ( SELECT 1 FROM trade_order o WHERE o.product_id = p.id AND o.deleted = 0 AND o.status IN ('待付款', '待发货', '待收货') )
AND p.service_type = #{serviceType}
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY p.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM sys_product p WHERE p.deleted = 0 AND p.status IN ('可用', '上架', '在售') AND (p.type = 'service' OR p.type IS NULL OR p.type = '') AND NOT EXISTS ( SELECT 1 FROM trade_order o WHERE o.product_id = p.id AND o.deleted = 0 AND o.status IN ('待付款', '待发货', '待收货') )
AND p.service_type = #{serviceType}
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))
